var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"토…… 토할 거 같아…….","JPN":"は……吐きそう……","ENG":"I... I think I'm going to throw up...","TWN":"我……我要吐了……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"이딴 게 공간 도약……? 차라리 죽고 말지, 우욱……!","JPN":"これが空間跳躍……？　死ぬ方がマシだよ、げえっ……！","ENG":"This is what the space jump is...? I'd rather die, urgh...!","TWN":"這就是空間跳躍嗎……？還不如乾脆去死，噁噁……！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"……더 이상 뭔가 시켰다간 차라리 뇌를 리셋시켜 버릴 테다.","JPN":"……これ以上私に何かをやらせる気なら、いっそこの頭脳をリセットしてやる。","ENG":"…If you give me one more task, I will reset my brain.","TWN":"……再叫我做什麼的話，大腦就要初始化了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"개인적인 고충은 잠시 참길 바란다!","JPN":"個人的な苦情は少し我慢しろ！","ENG":"Withhold all personal conflicts for now!","TWN":"個人的難處希望大家都先克服一下！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"전 대원, 상황을 보고하도록!","JPN":"全隊員、状況を報告しろ！","ENG":"All members, report!","TWN":"全體隊員，報告情況！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마! 전방에 적성 개체 반응 확인! 2종에 상당하는 녀석들뿐이야!","JPN":"おばさん！　前方に敵性個体の反応を確認！　2種に相当する奴らばかりよ！","ENG":"Maria! Hostiles detected in the front! They're all at least Category 2s!","TWN":"大嬸！前方感應到敵人個體反應！是相當於2類的傢伙！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"휘유, 이거 참 산 넘어 산인데?","JPN":"はあ、次から次と！","ENG":"*Whistle* It's always one thing after another.","TWN":"呼，這可真是困難重重啊？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어서 문 열어! 대장이 저 아래 있을 거라고!","JPN":"早くドアを開けろ！　きっと隊長はあそこにいる！","ENG":"Open up! Cap's down there!","TWN":"喂！快點開門！隊長在那下邊！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"얌전히 있어. 혼자 뛰어들다간 순식간에 다진 고기 꼴이 될 걸.","JPN":"大人しくここで待ちな。一人で飛び込んでもひき肉になって終わるだけだから。","ENG":"Stay still. You'll become ground meat if you rush out on your own.","TWN":"好好待著！這個高度掉下去，你想變成肉醬嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"현재 탑승한 전투원 전원, 강하 태세로 대기 중입니다.","JPN":"現在搭乗している戦闘員は全員、降下態勢で待機中です。","ENG":"All combatants onboard on standby, ready to drop.","TWN":"目前在艦船上的全體戰鬥人員，請隨時聽候命令。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"사령관님, 지시를.","JPN":"司令官、指示を。","ENG":"Awaiting your order, Commander.","TWN":"司令官，請下達指示。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"회장님, 잠시 힘을 빌릴 수 있겠습니까?","JPN":"会長、一瞬力をお借りしてもよろしいでしょうか？","ENG":"Miss Shin, would you lend me a hand for a moment?","TWN":"會長，可以暫時借助一下你的力量嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……아하.","JPN":"……なるほど。","ENG":"...Aha.","TWN":"……啊啊。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 물론이죠, 안토노프 사령관님. 여기가 바로 전환점이 될 테니까요.","JPN":"はい、もちろんです、アントノフ司令官。ここから巻き返しの時になるでしょうから。","ENG":"Of course, Commander Antonov. This will be the turning point.","TWN":"嗯，當然可以，安東諾夫司令官。從這裡開始就是轉捩點了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"전환점. 지금 상황에서 적절한 표현이군요.","JPN":"巻き返しの時。この状況にピッタリの表現です。","ENG":"Turning point. That's a nice way to put it.","TWN":"轉捩點。這個措辭很適合現在的情況呢。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"전 승조원 전투 태세로!","JPN":"全乗組員、戦闘態勢！","ENG":"All hands, get ready for battle!","TWN":"艦上全體人員，維持戰鬥之姿！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};